const SearchUserPage = () => {
  return (
    <Card
      style={{
        display: 'flex',
        height: '100%',
        marginLeft: '20px',
        marginRight: '20px',
        backgroundColor: "transparent",
        border: '1px solid rgba(140, 140, 140, 0.35)',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'space-around'
      }}
    >
      {/* 移除这里的 <Search> 组件 */}
      {searchResult &&
        <Card
          style={{ width: '500px', marginTop: '20px', height: '280px', backgroundColor: '' }}
        >
          <Avatar style={{ margin: '30px', backgroundColor: 'rgb(0,150,255)' }} size={70}>{searchResult[0]?.username}</Avatar>
          <Card.Meta
            description={searchResult[0]?.username}
            title=''
          />
          <Button onClick={AddFriends} style={{ marginTop: '10px', border: "0", backgroundColor: 'rgb(100,100,100,0.5)' }}>ADD</Button>
        </Card>}
    </Card>
  )
}

// 将 <Search> 放在 Contacts 组件中
<Content
  style={{
    padding: '0 50px',
    marginTop: "30px"
  }}
>
  <Layout
    style={{
      height: "100%",
      padding: '24px 0',
      backgroundColor: "rgb(255,255,255,0.5)",
      backdropFilter: "blur(10px)",
      WebkitBackdropFilter: "blur(10px)"
    }}
  >
    <Sider
      width={300}
      style={{
        backgroundColor: "transparent",
        fontSize: '20px'
      }}
    >
      <div
        id="scrollableDiv"
        style={{
          height: "100%",
          overflow: 'auto',
          padding: '0 16px',
          marginLeft: '20px',
          border: '1px solid rgba(140, 140, 140, 0.35)',
        }}
      >
        <Search
          size="large"
          style={{ width: '200px' }}
          onChange={e => setSearchUser(e.target.value)}
        ></Search>
        <Button size='large' onClick={handleAddFriends} ghost style={{ width: '100%', borderColor: 'rgba(140, 140, 140, 0.35)', marginTop: '10px' }}>ADD</Button>
        <InfiniteScroll
          dataLength={firendList.length}
          next={LoadContactList}
          hasMore={firendList.length < 50}
          endMessage={<Divider plain>It is all, nothing more 🤐</Divider>}
          scrollableTarget="scrollableDiv"
        >
          <List
            dataSource={firendList}
            renderItem={(item) => (
              <List.Item >
                <List.Item.Meta
                  avatar={<Avatar size={30} style={{ backgroundColor: "rgb(0,150,255)" }}>{item.username}</Avatar>}
                  title={item.username}
                />
                <div onClick={
                  () => {
                    setIsClick(false)
                    setSelectedUser(item)
                  }}>Content</div>
              </List.Item>
            )}
          />
        </InfiniteScroll>
      </div>
    </Sider>
    <Content>
      <ContentPage />
    </Content>
  </Layout>
</Content>
